using Contoso.Services;

namespace Contoso.Services.Tests;

[TestClass]
public sealed class ServiceRegistryTests
{
    private readonly ServiceRegistry _registry;

    public ServiceRegistryTests()
    {
        _registry = new ServiceRegistry();
    }

    [TestMethod]
    public void Register_AndResolve_ReturnsSameInstance()
    {
        var service = new FakeService();

        _registry.Register<IService>(service);
        var resolved = _registry.Resolve<IService>();

        Assert.AreSame(service, resolved);
    }

    [TestMethod]
    public void Resolve_UnregisteredService_ReturnsNull()
    {
        var result = _registry.Resolve<IService>();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void Clear_RemovesAllRegistrations()
    {
        _registry.Register<IService>(new FakeService());
        _registry.Register<IOtherService>(new FakeOtherService());

        _registry.Clear();

        Assert.IsNull(_registry.Resolve<IService>());
        Assert.IsNull(_registry.Resolve<IOtherService>());
    }

    [TestMethod]
    public void Remove_UnregistersSpecificService()
    {
        _registry.Register<IService>(new FakeService());
        _registry.Register<IOtherService>(new FakeOtherService());

        _registry.Remove<IService>();

        Assert.IsNull(_registry.Resolve<IService>());
        Assert.IsNotNull(_registry.Resolve<IOtherService>());
    }

    [TestMethod]
    public void Register_NullService_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _registry.Register<IService>(null!));
    }

    private interface IService;
    private interface IOtherService;
    private sealed class FakeService : IService;
    private sealed class FakeOtherService : IOtherService;
}

